import{_ as t,c as e,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"계정 추가: OAuth와 Refresh Token 이중 채널 | Antigravity Tools","description":"Antigravity Tools에서 계정을 추가하는 두 가지 방법을 학습합니다. OAuth 일회성 권한 부여 또는 Refresh Token 수동 추가를 통해 일괄 가져오기, 콜백 실패 처리, 계정 풀 확인을 지원합니다.","frontmatter":{"title":"계정 추가: OAuth와 Refresh Token 이중 채널 | Antigravity Tools","sidebarTitle":"Google 계정 추가","subtitle":"계정 추가: OAuth/Refresh Token 이중 채널과 모범 사례","description":"Antigravity Tools에서 계정을 추가하는 두 가지 방법을 학습합니다. OAuth 일회성 권한 부여 또는 Refresh Token 수동 추가를 통해 일괄 가져오기, 콜백 실패 처리, 계정 풀 확인을 지원합니다.","tags":["계정 관리","OAuth","refresh_token","Google","모범 사례"],"prerequisite":["start-getting-started"],"duration":15,"order":4},"headers":[],"relativePath":"ko/lbjlaq/Antigravity-Manager/start/add-account/index.md","filePath":"ko/lbjlaq/Antigravity-Manager/start/add-account/index.md"}'),c={name:"ko/lbjlaq/Antigravity-Manager/start/add-account/index.md"};function d(l,o,s,n,i,u){return r(),e("div",null,[...o[0]||(o[0]=[a('<h1 id="계정-추가-oauth-refresh-token-이중-채널과-모범-사례" tabindex="-1">계정 추가: OAuth/Refresh Token 이중 채널과 모범 사례 <a class="header-anchor" href="#계정-추가-oauth-refresh-token-이중-채널과-모범-사례" aria-label="Permalink to &quot;계정 추가: OAuth/Refresh Token 이중 채널과 모범 사례&quot;">​</a></h1><p>Antigravity Tools에서 &quot;계정 추가&quot;는 Google 계정의 <code>refresh_token</code>을 로컬 계정 풀에 작성하여 이후 역방향 프록시 요청에서 순환하여 사용할 수 있게 하는 것입니다. OAuth 일회성 권한 부여를 사용하거나 <code>refresh_token</code>을 직접 붙여넣어 수동으로 추가할 수 있습니다.</p><h2 id="학습-완료-후-가능한-작업" tabindex="-1">학습 완료 후 가능한 작업 <a class="header-anchor" href="#학습-완료-후-가능한-작업" aria-label="Permalink to &quot;학습 완료 후 가능한 작업&quot;">​</a></h2><ul><li>OAuth 또는 Refresh Token을 사용하여 Google 계정을 Antigravity Tools 계정 풀에 추가</li><li>권한 부여 링크 복사/수동 열기, 콜백 성공 후 자동으로 추가 완료</li><li><code>refresh_token</code>을 얻을 수 없거나 <code>localhost</code>에 연결할 수 없는 문제 발생 시 해결 방법 파악</li></ul><h2 id="현재-겪고-있는-문제" tabindex="-1">현재 겪고 있는 문제 <a class="header-anchor" href="#현재-겪고-있는-문제" aria-label="Permalink to &quot;현재 겪고 있는 문제&quot;">​</a></h2><ul><li>&quot;OAuth 권한 부여&quot;를 클릭했지만 계속 로딩 중이거나 브라우저에서 <code>localhost refused to connect</code> 오류 발생</li><li>권한 부여 성공 후 &quot;Refresh Token을 가져오지 못함&quot; 메시지 표시</li><li><code>refresh_token</code>만 가지고 있어서 일괄로 가져오는 방법을 모름</li></ul><h2 id="이-기능을-언제-사용해야-할까" tabindex="-1">이 기능을 언제 사용해야 할까 <a class="header-anchor" href="#이-기능을-언제-사용해야-할까" aria-label="Permalink to &quot;이 기능을 언제 사용해야 할까&quot;">​</a></h2><ul><li>계정을 가장 안정적인 방법으로 추가하고 싶을 때 (OAuth 우선)</li><li>마이그레이션 가능/백업 가능을 더 중요하게 생각할 때 (Refresh Token이 &quot;계정 풀 자산&quot;으로 더 적합)</li><li>많은 계정을 추가하고 <code>refresh_token</code>을 일괄로 가져오고 싶을 때 (텍스트/JSON에서 추출 지원)</li></ul><h2 id="🎒-시작-전-준비" tabindex="-1">🎒 시작 전 준비 <a class="header-anchor" href="#🎒-시작-전-준비" aria-label="Permalink to &quot;🎒 시작 전 준비&quot;">​</a></h2><ul><li>Antigravity Tools 데스크톱 버전을 설치하고 실행 가능한 상태</li><li>진입 경로 파악: 왼쪽 네비게이션에서 <code>Accounts</code> 페이지로 진입 (라우트는 <code>source/lbjlaq/Antigravity-Manager/src/App.tsx</code> 참조)</li></ul><div class="info custom-block"><p class="custom-block-title">이 수업에서 자주 등장하는 두 가지 핵심 키워드</p><p><strong>OAuth</strong>: &quot;브라우저로 이동하여 로그인하고 권한 부여&quot;하는 프로세스. Antigravity Tools는 로컬에 임시 콜백 주소를 생성 (<code>http://localhost/127.0.0.1/[::1]:&lt;port&gt;/oauth-callback</code>, 시스템 IPv4/IPv6 수신 상태에 따라 자동 선택)하고, 브라우저가 <code>code</code>를 가져오면 토큰으로 교환 (구현은 <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs</code> 참조)</p><p><strong>refresh_token</strong>: &quot;access_token을 장기적으로 갱신할 수 있는 자격 증명&quot;. 이 프로젝트에서 계정을 추가할 때 먼저 access_token으로 교환한 다음 Google에서 실제 이메일을 가져오고, 프론트엔드에서 입력한 email은 무시함 (구현은 <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs</code> 참조)</p></div><h2 id="핵심-개념" tabindex="-1">핵심 개념 <a class="header-anchor" href="#핵심-개념" aria-label="Permalink to &quot;핵심 개념&quot;">​</a></h2><p>Antigravity Tools의 &quot;계정 추가&quot;는 결국 사용 가능한 <code>refresh_token</code>을 확보하고 계정 정보를 로컬 계정 풀에 작성하는 것을 목표로 합니다.</p><ul><li><strong>OAuth 채널</strong>: 애플리케이션이 권한 부여 링크를 생성하고 로컬 콜백을 수신 대기; 권한 부여 완료 후 자동으로 토큰 교환 및 계정 저장 (<code>prepare_oauth_url</code>, <code>start_oauth_login</code>, <code>complete_oauth_login</code> 참조)</li><li><strong>Refresh Token 채널</strong>: <code>refresh_token</code>을 직접 붙여넣으면, 애플리케이션이 이를 사용하여 access_token을 갱신하고 Google에서 실제 이메일을 가져와서 저장 (<code>add_account</code> 참조)</li></ul><h2 id="함께-실습" tabindex="-1">함께 실습 <a class="header-anchor" href="#함께-실습" aria-label="Permalink to &quot;함께 실습&quot;">​</a></h2><h3 id="_1단계-계정-추가-대화상자-열기" tabindex="-1">1단계: &quot;계정 추가&quot; 대화상자 열기 <a class="header-anchor" href="#_1단계-계정-추가-대화상자-열기" aria-label="Permalink to &quot;1단계: &quot;계정 추가&quot; 대화상자 열기&quot;">​</a></h3><p><strong>이유</strong> 모든 추가 진입점은 <code>Accounts</code> 페이지에서 통합 관리됩니다.</p><p>작업: <code>Accounts</code> 페이지로 이동하여 오른쪽의 <strong>Add Account</strong> 버튼 클릭 (컴포넌트: <code>AddAccountDialog</code>).</p><p><strong>예상 화면</strong>: 3개의 탭을 포함하는 대화상자가 표시됨: <code>OAuth</code> / <code>Refresh Token</code> / <code>Import</code> (<code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx</code> 참조).</p><h3 id="_2단계-oauth-일회성-권한-부여-우선-사용-권장" tabindex="-1">2단계: OAuth 일회성 권한 부여 우선 사용 (권장) <a class="header-anchor" href="#_2단계-oauth-일회성-권한-부여-우선-사용-권장" aria-label="Permalink to &quot;2단계: OAuth 일회성 권한 부여 우선 사용 (권장)&quot;">​</a></h3><p><strong>이유</strong> 제품의 기본 권장 경로: 애플리케이션이 권한 부여 링크를 자동으로 생성하고 기본 브라우저를 열며, 콜백이 돌아오면 자동으로 저장 완료.</p><ol><li><code>OAuth</code> 탭으로 전환.</li><li>먼저 권한 부여 링크 복사: 대화상자가 열리면 자동으로 <code>prepare_oauth_url</code>을 호출하여 URL 미리 생성 (프론트엔드 호출은 <code>AddAccountDialog.tsx:111-125</code> 참조; 백엔드 생성 및 수신은 <code>oauth_server.rs</code> 참조).</li><li><strong>Start OAuth</strong> 클릭 (프론트엔드 <code>startOAuthLogin()</code> / 백엔드 <code>start_oauth_login</code> 해당), 애플리케이션이 기본 브라우저를 열고 콜백 대기 시작.</li></ol><p><strong>예상 화면</strong>:</p><ul><li>대화상자에 복사 가능한 권한 부여 링크 표시됨 (이벤트 이름: <code>oauth-url-generated</code>)</li><li>브라우저에서 Google 권한 부여 페이지 열림; 권한 부여 후 로컬 주소로 리디렉션되고 &quot;Authorization Successful!&quot; 표시됨 (<code>oauth_success_html()</code>)</li></ul><h3 id="_3단계-oauth가-자동으로-완료되지-않을-때-oauth-완료-로-수동-마무리" tabindex="-1">3단계: OAuth가 자동으로 완료되지 않을 때, &quot;OAuth 완료&quot;로 수동 마무리 <a class="header-anchor" href="#_3단계-oauth가-자동으로-완료되지-않을-때-oauth-완료-로-수동-마무리" aria-label="Permalink to &quot;3단계: OAuth가 자동으로 완료되지 않을 때, &quot;OAuth 완료&quot;로 수동 마무리&quot;">​</a></h3><p><strong>이유</strong> OAuth 프로세스는 두 단계로 나뉨: 브라우저 권한 부여로 <code>code</code> 획득, 그 다음 애플리케이션이 <code>code</code>로 토큰 교환. &quot;Start OAuth&quot;를 클릭하지 않더라도 권한 부여 링크를 수동으로 열고 콜백을 완료하면 대화상자가 자동으로 마무리 시도; 마무리 실패 시 수동으로 한 번 클릭.</p><ol><li>&quot;링크를 복사하여 자신의 브라우저에서 열기&quot;(기본 브라우저 아님)를 한 경우, 권한 부여 콜백이 돌아오면 애플리케이션이 <code>oauth-callback-received</code> 이벤트를 수신하고 자동으로 <code>completeOAuthLogin()</code> 호출 (<code>source/lbjlaq/Antigravity-Manager/src/components/accounts/AddAccountDialog.tsx:67-109</code> 참조).</li><li>자동 완료가 보이지 않으면, 대화상자에서 <strong>Finish OAuth</strong> 클릭 (백엔드 <code>complete_oauth_login</code> 해당).</li></ol><p><strong>예상 화면</strong>: 대화상자에서 성공 메시지 표시되고 자동으로 닫힘; <code>Accounts</code> 목록에 새 계정 표시됨.</p><div class="tip custom-block"><p class="custom-block-title">팁: 콜백 연결 실패 시 링크 복사 우선</p><p>백엔드는 가능한 한 IPv6 <code>::1</code>과 IPv4 <code>127.0.0.1</code>을 동시에 수신 대기하고, 수신 상태에 따라 <code>localhost/127.0.0.1/[::1]</code>을 콜백 주소로 선택. 주로 &quot;브라우저가 localhost를 IPv6로 해석&quot;으로 인한 연결 실패를 방지하기 위함 (<code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code> 참조).</p></div><h3 id="_4단계-refresh-token으로-수동-추가-일괄-지원" tabindex="-1">4단계: Refresh Token으로 수동 추가 (일괄 지원) <a class="header-anchor" href="#_4단계-refresh-token으로-수동-추가-일괄-지원" aria-label="Permalink to &quot;4단계: Refresh Token으로 수동 추가 (일괄 지원)&quot;">​</a></h3><p><strong>이유</strong><code>refresh_token</code>을 얻을 수 없거나(또는 &quot;마이그레이션 가능 자산&quot;을 더 선호할 때), Refresh Token으로 직접 추가하는 것이 더 제어 가능.</p><ol><li><code>Refresh Token</code> 탭으로 전환.</li><li><code>refresh_token</code>을 텍스트 상자에 붙여넣기.</li></ol><p>지원하는 입력 형식 (프론트엔드가 분석하여 일괄 추가):</p><table tabindex="0"><thead><tr><th>입력 유형</th><th>예시</th><th>분석 로직</th></tr></thead><tbody><tr><td>순수 토큰 텍스트</td><td><code>1//abc...</code></td><td>정규식 추출: <code>/1\\/\\/[a-zA-Z0-9_\\-]+/g</code> (<code>AddAccountDialog.tsx:213-220</code> 참조)</td></tr><tr><td>큰 텍스트 내에 포함</td><td>로그/내보내기 텍스트에 여러 개의 <code>1//...</code> 포함</td><td>정규식 일괄 추출 및 중복 제거 (<code>AddAccountDialog.tsx:213-224</code> 참조)</td></tr><tr><td>JSON 배열</td><td><code>[{&quot;refresh_token&quot;:&quot;1//...&quot;}]</code></td><td>배열 분석 후 <code>item.refresh_token</code> 추출 (<code>AddAccountDialog.tsx:198-207</code> 참조)</td></tr></tbody></table><p><strong>Confirm</strong> 클릭 후, 대화상자가 토큰 수량만큼 순차적으로 <code>onAdd(&quot;&quot;, token)</code> 호출 (<code>AddAccountDialog.tsx:231-248</code> 참조), 최종적으로 백엔드 <code>add_account</code>에 전달.</p><p><strong>예상 화면</strong>:</p><ul><li>대화상자에 일괄 진도 표시 (예: <code>1/5</code>)</li><li>성공 후 <code>Accounts</code> 목록에 새 계정 표시됨</li></ul><h3 id="_5단계-계정-풀-사용-가능-확인" tabindex="-1">5단계: &quot;계정 풀 사용 가능&quot; 확인 <a class="header-anchor" href="#_5단계-계정-풀-사용-가능-확인" aria-label="Permalink to &quot;5단계: &quot;계정 풀 사용 가능&quot; 확인&quot;">​</a></h3><p><strong>이유</strong> 추가 성공이 &quot;즉시 안정적으로 사용 가능&quot;을 의미하지 않음. 백엔드는 추가 후 자동으로 &quot;할당량 갱신&quot;을 트리거하고, Proxy 실행 시 토큰 풀 리로드를 시도하여 변경 즉시 적용.</p><p>다음 두 가지 신호로 확인:</p><ol><li>계정이 목록에 표시되고 이메일 표시됨 (이메일은 백엔드 <code>get_user_info</code>에서 옴, 입력한 email 아님).</li><li>계정 할당량/구독 정보 갱신 시작 (백엔드는 자동으로 <code>internal_refresh_account_quota</code> 호출).</li></ol><p><strong>예상 화면</strong>: 추가 후 수동으로 새로고침할 필요 없음, 계정에 할당량 정보 표시 시작 (성공 여부는 실제 UI 표시 기준).</p><h2 id="체크포인트-✅" tabindex="-1">체크포인트 ✅ <a class="header-anchor" href="#체크포인트-✅" aria-label="Permalink to &quot;체크포인트 ✅&quot;">​</a></h2><ul><li>계정 목록에서 새 계정의 이메일 확인 가능</li><li>&quot;loading&quot; 상태로 너무 오래 머물지 않음 (OAuth 콜백 완료 후 빨리 마무리되어야 함)</li><li>Proxy 실행 중인 경우, 새 계정이 빠르게 스케줄링에 참여 (백엔드는 리로드 시도)</li></ul><h2 id="흔한-오류" tabindex="-1">흔한 오류 <a class="header-anchor" href="#흔한-오류" aria-label="Permalink to &quot;흔한 오류&quot;">​</a></h2><h3 id="_1-oauth에서-refresh-token을-가져오지-못함-메시지" tabindex="-1">1) OAuth에서 &quot;Refresh Token을 가져오지 못함&quot; 메시지 <a class="header-anchor" href="#_1-oauth에서-refresh-token을-가져오지-못함-메시지" aria-label="Permalink to &quot;1) OAuth에서 &quot;Refresh Token을 가져오지 못함&quot; 메시지&quot;">​</a></h3><p>백엔드는 <code>start_oauth_login/complete_oauth_login</code>에서 <code>refresh_token</code> 존재 여부를 명시적으로 확인; 존재하지 않으면 해결 방법이 포함된 오류 메시지 반환 (<code>source/lbjlaq/Antigravity-Manager/src-tauri/src/commands/mod.rs:45-56</code> 참조).</p><p>소스 코드의 해결 방법:</p><ol><li><code>https://myaccount.google.com/permissions</code> 열기</li><li><strong>Antigravity Tools</strong>의 액세스 권한 취소</li><li>애플리케이션으로 돌아가 OAuth 다시 진행</li></ol><blockquote><p>이 수업의 Refresh Token 채널로 전환할 수도 있음.</p></blockquote><h3 id="_2-브라우저에서-localhost-refused-to-connect-메시지" tabindex="-1">2) 브라우저에서 <code>localhost refused to connect</code> 메시지 <a class="header-anchor" href="#_2-브라우저에서-localhost-refused-to-connect-메시지" aria-label="Permalink to &quot;2) 브라우저에서 `localhost refused to connect` 메시지&quot;">​</a></h3><p>OAuth 콜백은 브라우저가 로컬 콜백 주소를 요청해야 함. 실패율을 낮추기 위해 백엔드는:</p><ul><li><code>127.0.0.1</code>과 <code>::1</code>을 동시에 수신 대기 시도</li><li>둘 다 사용 가능할 때만 <code>localhost</code> 사용, 그렇지 않으면 강제로 <code>127.0.0.1</code> 또는 <code>[::1]</code> 사용</li></ul><p>해당 구현은 <code>source/lbjlaq/Antigravity-Manager/src-tauri/src/modules/oauth_server.rs:53-113</code> 참조.</p><h3 id="_3-다른-탭으로-전환하면-oauth-준비-취소" tabindex="-1">3) 다른 탭으로 전환하면 OAuth 준비 취소 <a class="header-anchor" href="#_3-다른-탭으로-전환하면-oauth-준비-취소" aria-label="Permalink to &quot;3) 다른 탭으로 전환하면 OAuth 준비 취소&quot;">​</a></h3><p>대화상자가 <code>OAuth</code>에서 다른 탭으로 전환하면, 프론트엔드는 <code>cancelOAuthLogin()</code>을 호출하고 URL을 비움 (<code>AddAccountDialog.tsx:127-136</code> 참조).</p><p>권한 부여 중인 경우, 탭을 전환하지 마세요.</p><h3 id="_4-refresh-token의-올바른-잘못된-예시" tabindex="-1">4) Refresh Token의 올바른/잘못된 예시 <a class="header-anchor" href="#_4-refresh-token의-올바른-잘못된-예시" aria-label="Permalink to &quot;4) Refresh Token의 올바른/잘못된 예시&quot;">​</a></h3><table tabindex="0"><thead><tr><th>예시</th><th>인식 여부</th><th>원인</th></tr></thead><tbody><tr><td><code>1//0gAbC...</code></td><td>✓</td><td><code>1//</code> 접두사 규칙 준수 (<code>AddAccountDialog.tsx:215-219</code> 참조)</td></tr><tr><td><code>ya29.a0...</code></td><td>✗</td><td>프론트엔드 추출 규칙 불일치, 잘못된 입력으로 간주됨</td></tr></tbody></table><h2 id="이-수업-요약" tabindex="-1">이 수업 요약 <a class="header-anchor" href="#이-수업-요약" aria-label="Permalink to &quot;이 수업 요약&quot;">​</a></h2><ul><li>OAuth: &quot;빠름&quot;에 적합, 링크를 복사하여 자주 사용하는 브라우저에서 열고 자동/수동으로 마무리 지원</li><li>Refresh Token: &quot;안정&quot;과 &quot;마이그레이션 가능&quot;에 적합, 텍스트/JSON에서 <code>1//...</code> 일괄 추출 지원</li><li><code>refresh_token</code>을 얻을 수 없을 때, 오류 메시지에 따라 권한 취소 후 재시도하거나 Refresh Token 채널로 전환</li></ul><h2 id="다음-수업-예고" tabindex="-1">다음 수업 예고 <a class="header-anchor" href="#다음-수업-예고" aria-label="Permalink to &quot;다음 수업 예고&quot;">​</a></h2><p>다음 수업에서는 더 확실한 작업을 수행합니다: 계정 풀을 &quot;마이그레이션 가능 자산&quot;으로 변환.</p><blockquote><p><strong><a href="./../backup-migrate/">계정 백업 및 마이그레이션: 가져오기/내보내기, V1/DB 핫 마이그레이션</a></strong> 학습.</p></blockquote><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>확장하여 소스 코드 위치 보기</strong></summary><blockquote><p>업데이트 시간: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>Accounts 페이지에 추가 대화상자 마운트</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Accounts.tsx#L267-L731" target="_blank" rel="noreferrer"><code>src/pages/Accounts.tsx</code></a></td><td>267-731</td></tr><tr><td>OAuth URL 미리 생성 + 콜백 이벤트 자동 마무리</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L49-L125" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>49-125</td></tr><tr><td>OAuth 콜백 이벤트가 <code>completeOAuthLogin()</code> 트리거</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L67-L109" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>67-109</td></tr><tr><td>Refresh Token 일괄 분석 및 중복 제거</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L185-L268" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>185-268</td></tr><tr><td>프론트엔드 Tauri commands 호출 (add/OAuth/cancel)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/services/accountService.ts#L5-L91" target="_blank" rel="noreferrer"><code>src/services/accountService.ts</code></a></td><td>5-91</td></tr><tr><td>백엔드 add_account: email 무시, refresh_token으로 실제 이메일 가져와서 저장</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L19-L60" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>19-60</td></tr><tr><td>백엔드 OAuth: refresh_token 누락 확인 및 권한 취소 해결 방법 제공</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L38-L79" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>38-79</td></tr><tr><td>OAuth 콜백 server: IPv4/IPv6 동시 수신 및 redirect_uri 선택</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/oauth_server.rs#L43-L113" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/oauth_server.rs</code></a></td><td>43-113</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>핵심 이벤트 이름</strong>:</p><ul><li><code>oauth-url-generated</code>: 백엔드에서 OAuth URL 생성 후 프론트엔드로 전송 (<code>oauth_server.rs:250-252</code> 참조)</li><li><code>oauth-callback-received</code>: 백엔드에서 콜백 수신 및 code 분석 후 프론트엔드에 알림 (<code>oauth_server.rs:177-180</code> / <code>oauth_server.rs:232-235</code> 참조)</li></ul><p><strong>핵심 명령</strong>:</p><ul><li><code>prepare_oauth_url</code>: 권한 부여 링크 미리 생성 및 콜백 수신 시작 (<code>src-tauri/src/commands/mod.rs:469-473</code> 참조)</li><li><code>start_oauth_login</code>: 기본 브라우저 열기 및 콜백 대기 (<code>src-tauri/src/commands/mod.rs:339-401</code> 참조)</li><li><code>complete_oauth_login</code>: 브라우저 열지 않고, 콜백만 대기하여 토큰 교환 완료 (<code>src-tauri/src/commands/mod.rs:405-467</code> 참조)</li><li><code>add_account</code>: refresh_token으로 계정 저장 (<code>src-tauri/src/commands/mod.rs:19-60</code> 참조)</li></ul></details>',67)])])}const q=t(c,[["render",d]]);export{g as __pageData,q as default};
